using UnityEngine;

public class PlayerMovement : MonoBehaviour
{
    private Rigidbody2D rb;
    private bool isGrounded;

    void Start()
    {
        rb = GetComponent<Rigidbody2D>();
    }

    void Update()
    {
        isGrounded = false; // Reset the flag at the start of every frame

        foreach (ContactPoint2D contact in rb.GetContacts(rb.bounds))
        {
            if (contact.normal.y >= 0.9f) // Check if the contact is with the ground
            {
                isGrounded = true;
            }
        }
    }
}
```

This script checks all the contacts the player's Rigidbody2D has and determines if any of them are with a surface (considering the y-axis normal vector to be close to 1 for ground detection).

By implementing these steps, your player should be able to walk on the ground without falling through.

