In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions, along with file descriptor redirection. Here's a simple example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <stdio.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid < 0) {  // Error
        perror("fork");
        return 1;
    } else if (pid == 0) {  // Child process
        // Close the write end of the pipe
        close(pipefd[1]);

        // Redirection: file descriptor 0 (stdin) is now connected to the read end of the pipe
        dup2(pipefd[0], 0);

        // Close the pipe read end
        close(pipefd[0]);

        // Execute the command, in this case, echo
        execlp("echo", "echo", "Hello, World!", (char*)NULL);
    } else {  // Parent process
        // Close the read end of the pipe
        close(pipefd[0]);

        // Write data to the pipe for the child process to read
        std::string data = "Hello from parent process!";
        write(pipefd[1], data.c_str(), data.size());

        // Close the write end
        close(pipefd[1]);

        // Wait for the child process to finish
        wait(NULL);
    }

    return 0;
}
```

This example uses a pipe to connect the child process's input/output with the parent's. The child process reads from the pipe and the parent writes to it.
